# name: corr_periodicity_diff
# description: The Pearson correlation between the difference in periodicity (periodicity_a - periodicity_b) and the choice of A.
def test_statistic(df):
    import numpy as np

    return float(
        np.corrcoef(df["periodicity_a"] - df["periodicity_b"], df["chose_left"])[0, 1]
    )

# name: periodicity_preference_controlled
# description: The choice rate for option A when it is more periodic than B, but has a similar alternation proportion (|p_alts_a - p_alts_b| <= 0.15).
def test_statistic(df):
    mask = (df["periodicity_a"] > df["periodicity_b"]) & (
        abs(df["p_alts_a"] - df["p_alts_b"]) <= 0.15
    )
    if mask.sum() == 0:
        return 0.0
    return float(df.loc[mask, "chose_left"].mean())

# name: over_alternating_vs_under_alternating
# description: The choice rate for option A when it is highly alternating (p_alts > 0.7) and option B is highly clumpy (p_alts < 0.5).
def test_statistic(df):
    mask = (df["p_alts_a"] > 0.7) & (df["p_alts_b"] < 0.5)
    if mask.sum() == 0:
        return 0.0
